-- PS1 — Langue française au service des cultures et de l'éducation
-- ═══════════════════════════════════════════════════════
INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A01', 'Langue française, langue internationale', 'Effets sur les diplomates et fonctionnaires internationaux',
   'acquisition_competences', 'Acquisition des compétences – Une montée en expertise largement constatée (pour plus de 75 % des agents formés)
Le projet « langue française, langue internationale » a essentiellement ciblé des professionnels de haut niveau, avec des profils issus des corps diplomatiques, des administrations nationales et des experts, et une partie relevant des organisations internationales.
Les résultats de l’enquête indiquent une meilleure compréhension du rôle et du fonctionnement des institutions internationales au niveau de plus de trois quarts des participants.
Les actions de formation mises en œuvre par le projet ont déclenché une véritable dynamique de montée en compétences : certains bénéficiaires ont renforcé leur aisance à s’exprimer en public, à argumenter et à débattre en français, ainsi qu’à rédiger efficacement des documents officiels et diplomatiques.', '75 %', 2024, 0);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A01', 'Langue française, langue internationale', 'Effets sur les diplomates et fonctionnaires internationaux',
   'effets_intermediaires', 'Utilisation des compétences – Une intégration concrète dans les pratiques professionnelles (pour plus de 56 % des agents formés)
Le second niveau de changement  réside dans la mobilisation effective des compétences développées par les diplomates et fonctionnaires internationaux dans leur environnement professionnel. Plus de la moitié des bénéficiaires formés indiquent avoir intégré les acquis de la formation dans leurs pratiques quotidiennes, notamment à travers une amélioration de la qualité rédactionnelle de leurs documents officiels, une plus grande rigueur dans la formulation de messages diplomatiques et une amélioration notable de leurs capacités d’intervention orale, ce qui leur permet de mieux représenter les positions nationales dans les forums internationaux et de s’exprimer avec plus d’aisance lors des négociations, des panels ou des réunions stratégiques.
Cette appropriation opérationnelle s’appuie sur un dispositif de formation contextualisé, pratique et progressif, qui a permis aux bénéficiaires de faire rapidement le lien entre les apprentissages reçus et les besoins concrets de leur fonction. En témoignent plusieurs recommandations émises par les agents, appelant à une régularité de ces formations et à leur spécialisation par thématique (relations internationales, diplomatie scientifique, égalité des genres, etc.).', '56 %', 2024, 1);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A01', 'Langue française, langue internationale', 'Effets sur les diplomates et fonctionnaires internationaux',
   'retombees', 'Retombées observées – Une valorisation professionnelle et des impacts organisationnels (pour plus de 20 % des agents ayant appliqué les acquis)
Les résultats des enquêtes indiquent que des bénéficiaires ayant mis en œuvre les acquis ont observé une transformation tangible dans leur trajectoire professionnelle ou au sein de leur organisation. Six participants ont accédé à des postes plus stratégiques ou enrichissants à la suite de la formation, montrant ainsi que celle-ci a constitué un levier de reconnaissance ou de mobilité ascendante dans leur carrière.
Sur le plan organisationnel, les fonctionnaires issus d’organisations internationales régionales (OIR) ont signalé plusieurs effets directs sur leur environnement de travail. Par exemple, des participants originaires du Cameroun, du Mozambique et de Serbie ont mentionné un renforcement des collaborations internationales, traduisant un effet multiplicateur du renforcement de capacités à l’échelle institutionnelle.
Enfin, les retours qualitatifs renforcent cette appréciation globale positive : les participants saluent la pertinence du programme mais formulent également des propositions d’amélioration qui témoignent de leur engagement. Parmi celles-ci figurent : la nécessité de renforcer l’immersion dans des environnements francophones, de favoriser les échanges en présentiel, d’intégrer des modules thématiques plus ciblés, ou encore d’accompagner la formation par une préparation à des certifications linguistiques spécialisées comme le DFP-RI (Diplôme de français professionnel – Relations internationales). L’ensemble de ces éléments confirme que le projet génère des effets positifs à la fois individuels et collectifs, tout en appelant à une consolidation dans la durée.', '20 %', 2024, 2);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A02', 'La langue française, langue d''enseignement', 'Effets de la mise en œuvre des actions',
   'acquisition_competences', 'Acquisition des compétences (pour plus de 51,6 % des )
Le dispositif a attiré une palette de besoins extrêmement diversifiée : près de la moitié des participants ont opté pour la session régionale de renforcement des compétences linguistiques et professionnelles, un peu plus d’un quart ont exploré l’intégration du numérique en français, langue étrangère (FLE), tandis qu’un peu plus d’un cinquième se sont tournés vers une approche grammaticale innovante et qu’environ un cinquième a découvert les applications de l’intelligence artificielle à l’enseignement du français. Cette variété témoigne d’un ancrage à la fois pragmatique et prospectif, offrant aux enseignants des ressources immédiatement opérationnelles.
L’ensemble des participants a salué avec force la qualité du contenu : une très large majorité a jugé les objectifs pédagogiques parfaitement définis et les supports entièrement adaptés à leurs enjeux de terrain. Les activités proposées ont été jugées hautement pertinentes, et l’animation du formateur, d’une clarté remarquable, a renforcé l’appropriation rapide des méthodes. Ces conditions idéales d’apprentissage se reflètent dans le taux d’assiduité et d’achèvement, plaçant le projet parmi les plus engageants jamais déployés.
Au final, un peu plus de la moitié des bénéficiaires reconnaissent avoir acquis des compétences qu’ils ne possédaient pas avant la formation et près des trois quarts constatent un gain net de connaissances. Cette montée en expertise, à la croisée de l’innovation numérique, des pratiques grammaticales renouvelées et des approches collaboratives, confirme la valeur ajoutée du projet : faire émerger chez chaque enseignant des savoir-faire nouveaux et durables, directement mobilisables pour transformer leurs pratiques de FLE.', '51,6 %', 2024, 10);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A02', 'La langue française, langue d''enseignement', 'Effets de la mise en œuvre des actions',
   'effets_intermediaires', 'Utilisation des compétences dans le quotidien pédagogique (pour plus de 94,0 % des
La quasi-totalité des enseignants formés (plus de neuf sur dix) ont immédiatement déployé les méthodes et outils acquis dans leur quotidien pédagogique.
Cette adoption ne se limite pas à un usage ponctuel des ressources : elle se traduit par l’intégration de scénarios interactifs, d’activités basées sur l’IA, et de séquences grammaticales innovantes, enrichies par les webinaires « Mon astuce en classe de FLE » et « Le sport en classe de FLE ». Les participants témoignent d’une mise en œuvre fluide des supports numériques, qu’il s’agisse de créations de modules multimédias ou de la réutilisation des guides de cours, démontrant ainsi une parfaite adéquation entre la formation et leurs exigences professionnelles.
Cette appropriation s’accompagne d’un renforcement sensible de la confiance en classe : deux enseignants sur trois se sentent désormais plus assurés lors de leurs interventions, grâce à l’usage d’outils interactifs et à la maîtrise d’approches différenciées adaptées à tous les niveaux. Par ailleurs, près de trois formateurs sur cinq rapportent un sentiment d’efficacité accrue, évoquant notamment une meilleure gestion du temps en séance, une capacité à maintenir l’attention des apprenants, et une plus grande créativité dans la conception de supports. Le format mixte (présentiel, distanciel, hybride) a par ailleurs joué un rôle décisif : la grande majorité des stagiaires s’accorde à dire qu’il a permis de maintenir une continuité pédagogique tout en offrant la flexibilité nécessaire aux contextes locaux.
Enfin, la collaboration entre pairs s’est intensifiée : enseignants et formateurs ont spontanément organisé des ateliers de partage pour expérimenter collectivement les approches apprises, construisant de véritables communautés de pratique. Ces espaces d’échange favorisent l’enrichissement mutuel et pérennisent l’utilisation des compétences, démontrant que la formation a su déclencher une dynamique collaborative durable.', '94,0 %', 2024, 11);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A02', 'La langue française, langue d''enseignement', 'Effets de la mise en œuvre des actions',
   'retombees', 'Autres retombées observées  (Pour plus de 59,9 % des )
La formation a déclenché un effet de levier significatif : près de six participants sur dix ont relayé les contenus auprès de leurs pairs, touchant chacun en moyenne une trentaine de collègues et, dans certains cas, jusqu’à mille personnes. Cette diffusion informelle a favorisé l’émergence de communautés de pratique dynamiques, où tuteurs, inspecteurs et enseignants partagent ressources, retours d’expérience et bonnes pratiques, consolidant ainsi le maillage pédagogique autour de l’approche par situations (APS).
Sur le plan individuel, presque trois formateurs sur cinq rapportent un niveau de performance sensiblement renforcé dans leurs missions quotidiennes, tandis que plus des deux tiers des stagiaires se déclarent aujourd’hui beaucoup plus confiants dans l’exercice de leur métier. Ces gains de confiance et d’efficacité s’illustrent par l’intégration durable des outils numériques et méthodologies IFADEM dans les programmations pédagogiques et la gestion de classe.
A l’échelle institutionnelle, ces retombées ont conduit plusieurs établissements à formaliser l’usage des dispositifs acquis : révision des plans de formation interne, adoption systématique des webinaires thématiques et reconnaissance officielle des APS comme partie intégrante du curriculum.
Enfin, les changements sur les apprenants sont déjà visibles : les enseignants rapportent une meilleure motivation de leurs classes, une participation accrue aux activités orales et des progrès mesurables en expression écrite. Ces gains pédagogiques, conjugués à la construction de réseaux d’échanges et à une confiance professionnelle renouvelée, confirment que le projet « Langue d’enseignement et d’apprentissage » a généré une transformation durable, posant les bases d’une culture de l’innovation et de la qualité en FLE dans l’espace francophone.', '59,9 %', 2024, 12);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A03', 'IFADEM — Initiative francophone pour la Formation à Distance des Maîtres', 'Effets de la mise en œuvre des actions IFADEM',
   'acquisition_competences', 'Acquisition des compétences  pour plus de 99 % des agents formés– Une montée en compétences massive et différenciée des enseignants.
Le projet IFADEM a conduit les enseignants à repenser en profondeur leur préparation de cours : ils planifient désormais leurs séquences en intégrant systématiquement des situations d’apprentissage contextualisées, structurent chaque séance autour d’objectifs clairs et adaptent leurs activités au profil de leurs élèves. Cette approche par situations, autrefois réservée aux manuels, est aujourd’hui mise en œuvre dans la classe, permettant d’articuler démarches inductives et moments de mise en commun, et de favoriser l’engagement de tous, y compris des élèves en difficulté. Sur le plan de la différenciation pédagogique, les enseignants déploient de nouvelles stratégies pour prendre en compte la diversité des niveaux : création de sous-groupes, ateliers de remédiation et activités complémentaires sont désormais intégrés dans le déroulé quotidien. Ils maîtrisent mieux l’articulation entre travail individuel et travail collaboratif, et savent identifier les compétences à remobiliser chez chaque élève, ce qui se traduit par une progression visible de la participation en classe et de la qualité des productions écrites.
L’appropriation des outils numériques constitue un autre point clé : les formateurs d’IFADEM (100% en ligne) ont guidé les enseignants dans l’usage de la plateforme en ligne, des livrets interactifs et des applications mobiles. À leur retour, ceux-ci savent non seulement piloter des modules à distance, mais aussi créer et partager leurs propres ressources (vidéos, quiz, supports audio), favorisant ainsi l’échange et l’entraide entre pairs. Plusieurs participants témoignent d’une aisance nouvelle pour organiser des réunions virtuelles et animer des réseaux d’enseignants locaux. Le projet a également encouragé le développement d’une culture de la collaboration et du tutorat : les enseignants expérimentés et novices travaillent côte à côte pour co-construire des séquences, relire mutuellement leurs projets et mettre en place des ateliers de formation interne. Cette dynamique de capitalisation et de diffusion des bonnes pratiques assure une pérennité des innovations, chaque établissement devenant un véritable laboratoire d’expérimentation pédagogique au sein du réseau francophone.', '99 %', 2024, 20);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A03', 'IFADEM — Initiative francophone pour la Formation à Distance des Maîtres', 'Effets de la mise en œuvre des actions IFADEM',
   'effets_intermediaires', 'Utilisation des compétences – Une mise en pratique quasi systématique (pour plus de 97 % des agents formés)
Au cœur de leur pratique quotidienne, les enseignants transposent désormais sans difficulté les méthodes et outils IFADEM. Ils construisent leurs séquences autour de situations d’apprentissage contextualisées, exploitent le programme national revisité et adaptent les livrets aux besoins de chaque groupe même lorsque les classes sont surchargées ou que les moyens techniques font défaut. Certains racontent comment des professeurs, jusque-là peu à l’aise avec la grammaire ou la rédaction, animent aujourd’hui des ateliers de remise à niveau avec assurance, grâce aux démarches méthodologiques et aux ressources numériques qu’ils ont eux-mêmes créées. Cette appropriation ne se limite pas à une application individuelle : elle irrigue l’ensemble de la communauté éducative. Les formés organisent des sessions de co-tutorat, partagent en réseau leurs supports numériques et, dans plusieurs établissements, instaurent des clubs d’échange où chaque enseignant peut présenter ses innovations. Un témoignage marquant évoque un pair qui, sceptique au départ, a rapidement adopté l’approche par situations après avoir vu l’éveil et la confiance renaître chez ses élèves.
Par ailleurs, l’usage régulier des outils de suivi – grilles d’évaluation, capsules vidéo, quizz en ligne – crée un réflexe de pilotage de la progression des élèves : les enseignants ajustent leurs activités en temps réel, analysent les difficultés et proposent immédiatement des remédiations ciblées. Certains soulignent même qu’ils parviennent à encadrer de jeunes stagiaires en reproduisant fidèlement le dispositif IFADEM, ce qui témoigne d’un effet multiplicateur précieux. L’environnement pédagogique, jugé très proche des réalités de terrain, renforce cette dynamique : la formation a su proposer des formats modulables et des ressources immédiatement exploitables, favorisant un lien étroit entre théorie et pratique. Résultat : IFADEM ne se contente pas d’enrichir les compétences individuelles, il transforme progressivement la culture d’établissement et instaure une logique de collaboration, d’expérimentation et de partage qui perdure bien au-delà des sessions de formation.', '97 %', 2024, 21);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A03', 'IFADEM — Initiative francophone pour la Formation à Distance des Maîtres', 'Effets de la mise en œuvre des actions IFADEM',
   'retombees', 'Retombées observées – Des effets visibles sur les enseignants, les élèves et les trajectoires professionnelles (pour plus de 50 % des agents ayant appliqué les acquis)
Les participants reviennent rarement indemnes de leur expérience IFADEM : nombreux sont ceux qui évoquent un véritable changement de regard sur leur métier et leurs élèves. Ils soulignent comment, dès la rentrée suivante, leurs cours sont structurés autour de scénarios pédagogiques vivants, favorisant l’engagement de chaque apprenant, jusque dans les classes les plus surchargées. Un enseignant raconte qu’il ne peut désormais plus se passer de ses “situations” : « J’ai vu mes élèves, habituellement en retrait, prendre la parole, confronter leurs analyses et soutenir leurs arguments, c’est devenu notre rituel hebdomadaire. » Dans la gestion de classe, la mise en œuvre des techniques apprises se manifeste par une atmosphère plus collaborative et un climat de confiance renouvelé. Les enseignants instaurent des ateliers en petits groupes, des sessions de remédiation rapide et des conseils croisés entre collègues, transformant la salle de classe en un véritable atelier de co-construction du savoir. Plusieurs formateurs évoquent leur fierté de voir des professeurs débutants guider à leur tour des stagiaires, prolongeant ainsi l’effet domino de la formation.
Les retombées vont au-delà des murs de l’école : les anciens participants se voient souvent confier des responsabilités élargies, animation de séminaires, conception de ressources pour l’académie, voire participation à des projets de réforme locale. L’un d’eux se souvient : « Après IFADEM, j’ai été invité à piloter la révision du manuel de français de mon district, un signe que mes compétences étaient désormais reconnues au plus haut niveau. »
Enfin, c’est tout le système éducatif qui se trouve dynamisé. Des établissements entiers adoptent progressivement les outils numériques partagés, les grilles de suivi et les modules d’apprentissage par situations, donnant naissance à des réseaux de pratique où les innovations se diffusent rapidement d’une école à l’autre. Les témoignages convergent : IFADEM n’est pas une simple formation, c’est un moteur de transformation, capable de redessiner durablement le paysage pédagogique et la place de la Francophonie dans chaque classe.', '50 %', 2024, 22);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A04', 'ELAN — École et Langues nationales', 'Effets de la mise en œuvre des actions ELAN',
   'acquisition_competences', 'Acquisition des compétences  (Pour plus de 95 % des enseignants renforcent leurs pratiques pédagogiques et linguistiques)
Le projet ELAN se révèle particulièrement efficace dans le développement des compétences pédagogiques et linguistiques en contexte bilingue. Il place la langue maternelle au cœur des apprentissages en donnant aux enseignants les clés pour concevoir eux-mêmes des supports didactiques adaptés. Ils maîtrisent désormais la création de séquences intégrant chants, comptines et jeux linguistiques, ce qui a dynamisé l’apprentissage de l’alphabet et des premiers textes. Cette maîtrise se double d’une aisance nouvelle dans la lecture et la production écrite, tant en français qu’en langues nationales, permettant d’aborder des contenus plus complexes dès les premiers niveaux.
Les bénéficiaires rapportent avoir renforcé leur maîtrise des langues nationales, amélioré leurs pratiques de lecture-écriture, et affiné leur compréhension de l’apprentissage initial en langue maternelle. Certains témoignages illustrent une appropriation linguistique profonde : « J’ai enrichi ma connaissance de ma langue maternelle et compris des mots que j’utilisais sans en saisir le vrai sens », ou encore : « Grâce à la formation, je suis désormais capable d’enseigner en dioula ce que j’enseignais auparavant uniquement en français ».
Par ailleurs, la qualité de la formation, l’accueil et l’accompagnement des formateurs sont unanimement salués : « Tous les formateurs sont à notre disposition, très explicites, à l’écoute, et motivants ». Cette approche de proximité a permis une montée en compétence différenciée, y compris chez des enseignants initialement réticents ou peu à l’aise avec les techniques bilingues.', '95 %', 2024, 30);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A04', 'ELAN — École et Langues nationales', 'Effets de la mise en œuvre des actions ELAN',
   'effets_intermediaires', 'Utilisation des compétences – Une application massive et contextualisée dans les pratiques pédagogiques (près de 100 % des enseignants)
L’analyse des données montre une transposition quasi systématique des compétences acquises dans les pratiques pédagogiques quotidiennes. En effet, les professeurs orchestrent désormais leurs leçons autour d’activités linguistiques vivantes, comptines pour l’apprentissage de l’alphabet, jeux de rôle et lectures partagées, même dans des écoles aux effectifs conséquents ou aux moyens limités. Ce passage de la théorie à l’usage quotidien transforme la relation élève-enseignant :  pour certains élèves autrefois silencieux, l’approche bilingue vient créer un espace d’expression, renforçant leur engagement et leur estime de soi. Cette appropriation dépasse la simple répétition de contenus : elle touche les modalités de gestion de classe, les techniques d’animation et l’organisation de l’apprentissage en langues nationales.
Les témoignages confirment une mise en œuvre dynamique : « Mes élèves de CP1 lisent désormais des textes longs avec fluidité », « L’usage des comptines pour apprendre l’alphabet stimule la mémorisation », ou encore « L’intégration de la langue maternelle lève les barrières de compréhension et facilite l’engagement des élèves ». D’autres enseignants décrivent comment, à travers l’approche ELAN, ils ont repensé entièrement leurs séquences didactiques, incluant des activités orales, l’illustration de textes ou des jeux pédagogiques en langues locales.
Plus encore, cette appropriation s’est doublée d’une dynamique collaborative inédite. Les enseignants s’entretiennent régulièrement en ateliers de co-tutorat, y exposent leurs retours d’expérience et ajustent collectivement leurs supports, des livrets revisités aux activités de différenciation en petits groupes. Nombre d’entre eux confient que, ayant observé l’enthousiasme et les progrès de leurs élèves, ils ne sauraient aujourd’hui envisager un retour à la pédagogie uni-lingue. Par cette mise en réseau des savoir-faire, le projet ELAN affirme ainsi sa dimension structurante : non seulement il enrichit la pratique individuelle mais en plus il initie une mutation culturelle profonde au sein de la communauté éducative francophone. En somme, les compétences acquises ont été rapidement internalisées, transférées et déployées dans les classes, avec des effets multiplicateurs sur l’ensemble du corps enseignant impliqué.', '100 %', 2024, 31);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A04', 'ELAN — École et Langues nationales', 'Effets de la mise en œuvre des actions ELAN',
   'retombees', 'Retombées observées – Une transformation pédagogique tangible et des partenariats structurants pour la pérennité du dispositif
Les retombées de la mise en œuvre du projet ELAN sont à la fois pédagogiques, institutionnelles et systémiques, marquant un tournant dans l’enseignement bilingue et l’intégration des langues nationales. La quasi-totalité des enseignants formés rapporte avoir observé une nette progression des performances scolaires et une participation active renforcée, y compris parmi les élèves les plus en difficulté. Des témoignages révèlent que « des élèves de CP1 écrivent désormais avec fluidité » ou que « les performances à l’examen du CEP ont atteint 100 % dans les premières promotions ELAN ». Les enseignants relatent une nouvelle proximité avec les élèves et leurs familles, grâce à l’enseignement en langue locale qui facilite la compréhension, le lien affectif et l’implication des parents dans le parcours éducatif.
Au niveau professionnel, les enseignants rapportent une valorisation de leurs compétences, une meilleure maîtrise de la didactique bilingue et un usage plus pertinent des ressources pédagogiques adaptées. L’effet est aussi institutionnel : certaines écoles ont modifié leurs pratiques internes, renforcé le suivi pédagogique et mis en place des environnements d’apprentissage plus inclusifs.
Ces retombées positives sont consolidées par un écosystème de partenariats stratégiques, qui contribuent à l’ancrage du projet dans les systèmes éducatifs nationaux. L’implication des ministères de l’Éducation et de la Culture, des maisons d’édition, de l’Institut de Linguistique Appliquée (ILA), des fédérations de parents d’élèves et des syndicats enseignants a permis une co-construction des ressources, une mutualisation des savoirs et un engagement partagé pour la qualité. En complément, le soutien de partenaires techniques et financiers (CONFEMEN/PASEC, IFADEM, OIF, etc.) a permis de développer des projets pilotes, de renforcer les capacités locales (formations, reprographie, distribution de manuels) et de mobiliser des fonds par des stratégies de plaidoyer ciblées.
Enfin, la coopération Sud-Sud et l’engagement du secteur privé ont permis de tester des innovations en contexte réel et de renforcer l’autonomie des dispositifs nationaux. En somme, le projet ELAN génère des effets durables et reproductibles, soutenus par une architecture partenariale cohérente, fédératrice et adaptable, garantissant la pérennité des transformations amorcées dans les systèmes éducatifs francophones.', '100 %', 2024, 32);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A05', 'CLAC — Centres de Lecture et d''Animation Culturelle', 'Effets de la mise en œuvre des actions CLAC',
   'acquisition_competences', 'Acquisition des compétences – Un bouquet de savoirs et savoir-faire pour plus de 98 % des usagers formés', '98 %', 2024, 40);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A05', 'CLAC — Centres de Lecture et d''Animation Culturelle', 'Effets de la mise en œuvre des actions CLAC',
   'effets_intermediaires', 'Le projet CLAC a offert un environnement d’apprentissage hybride combinant ressources imprimées, numériques et animations culturelles, aboutissant à une acquisition multidimensionnelle des compétences. Cette diversité des dispositifs de médiatisation a permis aux usagers de développer simultanément des compétences variées : de la recherche documentaire à la lecture critique, en passant par l’adaptation de contenus et la création de supports pédagogiques. Les ateliers d’initiation aux outils en ligne, couplés à des rencontres thématiques, ont favorisé une appropriation fluide des savoir-faire enseignés, confortant le CLAC dans sa mission de « laboratoire » éducatif innovant et de canal d’accès à la culture. Sur le plan professionnel, les bénéficiaires témoignent d’une montée en expertise tangible : nombreux sont ceux qui conçoivent désormais et pilotent des projets locaux, animent des ateliers thématiques ou élaborent des guides pratiques destinés à leur communauté. La pratique régulière de la langue française, combinée à l’utilisation des langues nationales, a enrichi leur expression orale et écrite.
Plus de la moitié des usagers se sent désormais plus indépendant dans leur apprentissage et la recherche d’informations : la plupart des usagers déclarent naviguer aujourd’hui en toute confiance sur les plateformes numériques, exploiter des bases de données spécialisées et échanger directement avec les équipes du projet CLAC pour enrichir leurs connaissances. « J’étais un novice du web et j’ai appris à exploiter efficacement les ressources en ligne » confie l’un d’eux. Cette indépendance accrue dans la recherche et la gestion de l’information contribue à renforcer leur professionnalisme et leur sentiment de responsabilité.
Sur le plan culturel et citoyen, les CLAC s’affirment comme un puissant moteur d’ouverture culturelle et d’engagement citoyen. Les ateliers de découverte d’auteurs locaux, les séances de contes intergénérationnels et les clubs de lecture participent à une meilleure compréhension des pratiques traditionnelles et à la valorisation du patrimoine. Plusieurs porteurs de projet évoquent la co-élaboration d’initiatives artistiques tandis que d’autres ont lancé des clubs de lecture ou des forums d’échange sur des thématiques sociales. En fédérant ministères, maisons d’édition, collectivités et autorités locales, associations de parents et acteurs locaux etc., le CLAC tisse un réseau partenarial solide, garant de la pérennité de ces dynamiques et de l’impact durable sur le développement individuel et collectif.
Utilisation des compétences – Une appropriation multiforme et impactante  (plus de 90 % des usagers formés)
L’enquête révèle que l’accès régulier aux CLAC se traduit par une application concrète et diversifiée des compétences acquises. Les usagers observent une amélioration palpable de leurs pratiques professionnelles, notamment dans la production de documents, l’animation d’ateliers et la conduite de projets locaux. Cette montée en ', '90 %', 2024, 41);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A05', 'CLAC — Centres de Lecture et d''Animation Culturelle', 'Effets de la mise en œuvre des actions CLAC',
   'retombees', 'Retombées observées – Des impacts durables sur l’emploi, la cohésion sociale et l’engagement communautaire (plus de 70 % des usagers impliqués)
Les CLAC se sont imposés comme de véritables tremplins de carrière, ouvrant à leurs usagers des perspectives professionnelles jusque-là inaccessibles. Plusieurs témoignages en attestent : des fonctionnaires qui ont vu leur profil confirmé par un contrat de deux ans, d’anciens adhérents devenus animateurs salariés ou encore des metteurs en scène reconnus, tous rapportent que leur passage au CLAC a constitué un véritable franchissement d’étape dans leur parcours. En redynamisant leur maîtrise de l’écrit, de l’oral et de la recherche documentaire, ces espaces transcendent le simple principe de consultation pour façonner des trajectoires nouvelles et valorisantes.
Sur le plan scolaire, l’effet est tout aussi spectaculaire. Nombre d’élèves, autrefois rétifs à la lecture, y trouvent désormais un cadre stimulant où combler leurs lacunes et cultiver leur goût de l’apprentissage. Plusieurs jeunes affirment avoir obtenu leur BEPC grâce à l’accès régulier aux ouvrages et aux ateliers de soutien tandis que d’autres témoignent spontanément de notes en hausse en français et en histoire-géographieLe CLAC, par sa combinaison de temps de lecture guidée et de travaux en petits groupes, transforme le rapport à l’étude et offre un accompagnement sur mesure qui porte ses fruits dès les évaluations.
Mais le véritable atout du CLAC réside peut-être dans son rôle de catalyseur de cohésion sociale. Les concours artistiques, clubs de lecture et autres animations thématiques fédèrent toutes les générations et renforcent le lien entre les habitants. Un organisateur confie encore l’enthousiasme suscité par le premier concours « Percu Vacances » : l’ensemble de la communauté a réclamé une deuxième édition. Les jeunes et les femmes, en particulier, y trouvent un espace d’expression et d’engagement, en participant à la mise en place de projets culturels, de débats publics et de rendez-vous intergénérationnels.
Cette dynamique se nourrit d’une relation forte et pérenne avec le CLAC : les abonnés y reviennent semaine après semaine, séduits par la diversité des collections et par une modernisation progressive des équipements. Tout en saluant la richesse des romans, bandes dessinées et documentaires, nombreux sont ceux qui appellent aujourd’hui à un renforcement des moyens numériques ordinateurs, tablettes, connexion illimitée pour étendre encore davantage la portée de ces lieux. Plus qu’un centre de ressources, le CLAC est ainsi devenu un laboratoire d’innovation sociale, conjuguant insertion professionnelle, réussite académique et vitalité communautaire.', '70 %', 2024, 42);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A06', 'Industrie culturelle et découvrabilité des contenus francophones', 'Effets des actions sur l''industrie culturelle francophone',
   'acquisition_competences', 'Acquisition des compétences – Un renforcement technique, artistique et stratégique des porteurs de projets
Le projet industrie culturelle et  découvrabilité a engendré une amélioration tangible des compétences de ses bénéficiaires tant sur le plan artistique que stratégique. Parmi les porteurs de projets audiovisuels interrogés, les trois quarts confirment un gain significatif en qualité technique et artistique, retouches audio, maîtrise de l’éclairage, cadrages plus soignés ou bande-son enrichie. Cette progression trouve écho dans la satisfaction globale, où la quasi-totalité des participants se disent « satisfaits » ou « très satisfaits » du soutien méthodologique et technique apporté.
Au-delà de l’artisanat cinématographique, le projet a également favorisé une véritable montée en compétences stratégiques. Des porteurs de projets rapportent des transformations concrètes dans leur activité ou leur structure, l’adaptation de leur modèle économique, une meilleure gestion de projet, la capacité à négocier des financements. Parmi eux, les trois quarts soulignent une explosion de créativité et le lancement de nouveaux projets, d’autres relèvent une meilleure vision stratégique de leur marché et citent une montée en compétences spécifiques (scénarisation, montage avancé, stratégies de diffusion). Plusieurs témoignages illustrent ces acquis :« Les ateliers sur la découvrabilité m’ont appris à structurer une campagne de promotion en ligne » témoigne un réalisateur. « Grâce au coaching sur la gestion de la lumière et du son, j’ai pu finaliser un pilote de série de qualité professionnelle » confie une productrice.
Ces retours que confirment le projet agit comme un véritable catalyseur de compétences multicouches, permettant aux porteurs de projets de maîtriser les outils artistiques tout en intégrant une démarche stratégique pour pérenniser et valoriser leurs œuvres.', NULL, 2024, 50);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A06', 'Industrie culturelle et découvrabilité des contenus francophones', 'Effets des actions sur l''industrie culturelle francophone',
   'effets_intermediaires', 'Utilisation des compétences – Un déploiement actif et partenarial (jusqu’à 59,5 % de réseautage)
Les porteurs de projets formés dans le cadre du projet Industrie culturelle et découvrabilité ne se contentent pas d’appliquer isolément les compétences acquises. La formation a impulsé chez les porteurs de projets un véritable élan de coopération et de mise en réseau : ils ne se contentent plus de développer leurs œuvres en atelier mais s’engagent activement dans la construction de partenariats durables avec d’autres cinéastes, éditeurs et diffuseurs. Sur le terrain, les répondants se sentent désormais bien informés et/ou actifs soit individuellement, soit collectivement dans des actions de découvrabilité. Concrètement, ces porteurs ont détaillé des démarches participatives incluant :  ateliers de sensibilisation et formations à la stratégie éditoriale et aux réseaux sociaux pour renforcer la visibilité des œuvres francophones | Médiation et pilotage d’événements emblématiques (MASA 2024 : 300 spectacles, 2 000 artistes) et conférences thématiques au Bénin ou  | Master-class, émissions radio et reportages en ligne, qui servent à valoriser médiatiquement les créations locales (ex. série « À la recherche du légume star » à Cannes)| Soutien technique à l’inscription et à la mise en valeur des films sur des plateformes spécialisées (laplateforme.be) facilitant l’accès pour les enseignants et professionnels.
Ce déploiement concret des compétences est renforcé par un partenariat technique et financier bien structuré, mobilisant également le secteur privé, les fondations et la coopération Sud-Sud, et validé par des stratégies de plaidoyer pour lever des financements complémentaires.
En somme, les compétences acquises s’intègrent dans un écosystème partenarial robuste garantissant un déploiement opérationnel et une découvrabilité accrue des œuvres francophones à l’échelle aussi bien locale, régionale qu’internationale.', '59,5 %', 2024, 51);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS1', 'PROJ_A06', 'Industrie culturelle et découvrabilité des contenus francophones', 'Effets des actions sur l''industrie culturelle francophone',
   'retombees', 'Retombées observées – Un effet catalyseur sur les trajectoires et l’écosystème culturel (jusqu’à 86 % de transformations)
La quasi-totalité des porteurs de projets évoquent une transformation profonde de leurs pratiques et de leur trajectoire professionnelle nourrie par l’appui méthodologique et technique du dispositif. Beaucoup soulignent que ce soutien a non seulement élargi leur palette artistique mais qu’il a surtout insufflé une véritable audace créative. Ainsi, plusieurs réalisations inédites ont vu le jour : de nouveaux formats de séries et de documentaires ont été conçus, des workshops expérimentaux se sont imposés comme terrains de jeu pour l’innovation, et l’ensemble du processus de scénarisation a gagné en rigueur et en inventivité.
Parmi ceux qui ont vu leur activité évoluer, nombreux sont ceux qui évoquent un enrichissement de la dimension stratégique de leur démarche. L’atelier dédié à la découvrabilité, par exemple, a été salué pour avoir permis à certains de structurer des campagnes de promotion en ligne et de négocier plus efficacement des soutiens financiers. Un réalisateur se souvient d’avoir été invité à concourir à Cannes ACID grâce à la qualité de son pilote « La sélection à Cannes ACID 2023 a été un formidable coup de projecteur : non seulement j’ai gagné en confiance, mais j’ai obtenu les financements nécessaires pour tourner mon pilote. ». De même une productrice témoigne d’un mandat de conseil auprès d’autorités nationales pour la modernisation du statut de l’artiste. « Suite à l’atelier sur la découvrabilité, j’ai été invité comme consultant pour actualiser la loi sur le statut de l’artiste au Bénin. »
Les effets structurants dépassent l’individu pour irriguer l’ensemble de l’écosystème. Les porteurs de projet soulignent un élargissement de leur réseau professionnel et la création de partenariats durables (IFLA, maisons d’édition, diffuseurs, plateformes en ligne). Des actions concrètes ont émergé : MASA 2024 (300 spectacles, 2 000 artistes, 500 000 spectateurs) monté en collaboration avec des comités d’experts ICC, Short Film Corner à Cannes où la série « À la recherche du légume star » a été diffusée, master-class et émissions radio dédiées à la promotion des créateurs francophones, ateliers de stratégie éditoriale pour la valorisation sur réseaux sociaux et plateformes spécialisées (laplateforme.be). Enfin, le projet a également agi comme moteur de changement institutionnel et réglementaire :  contribution à l’actualisation de conventions collectives et lois cinématographiques (CNC, statut de l’artiste),  plaidoyer pour la découvrabilité des œuvres, entraînant un engagement accru des pouvoirs publics et des bailleurs, renforcement du modèle économique des porteurs via la validation de plans de financement et l’accès à des fonds complémentaires.
En somme, les actions menées revêtent le caractère d’un levier d’innovation, d’un accélérateur de carrières et un facteur de structuration durable de l’écosystème culturel fra', '86 %', 2024, 52);

-- ═══════════════════════════════════════════════════════
-- PS2 — Langue française au service de la démocratie et de la gouvernance
-- ═══════════════════════════════════════════════════════
INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS2', 'PROJ_A09', 'État civil', 'Effets des actions de modernisation de l''état civil',
   'synthese', 'L’engagement politique de l’OIF en faveur de la modernisation et de la généralisation de l’enregistrement des faits d’état civil dans les pays francophones se matérialise à travers le projet «Etat civil ». Les effets des actions de ce projets se traduisent à différents niveaux :
Acquisition des compétences pour 100% des agents formés
L’analyse qualitative des compétences acquises ou renforcées par les participants met en lumière une diversité de savoirs pratiques et théoriques liés à l’état civil, traduisant une appropriation étendue et contextualisée des enjeux du secteur.
Les participants rapportent avoir renforcé leurs capacités techniques relatives aux procédures d’état civil, notamment dans l’enregistrement des naissances, reconnaissances, adoptions et décès, ainsi que dans la maîtrise des conduites à tenir pour chaque type d’enregistrement. Ces éléments démontrent une bonne compréhension des procédures administratives essentielles.
En parallèle, des compétences fonctionnelles ont été développées, facilitant l’exécution des tâches au quotidien. Cela inclut la facilitation des tâches liées à la fonction, la responsabilité en tant qu’agent d’état civil, ainsi que la capacité à accueillir et orienter les usagers. Ces acquis favorisent un service plus fluide, efficace et centré sur l’usager.
Sur le plan éthique et sociétal, plusieurs répondants ont évoqué l’acquisition de compétences transversales telles que la sensibilisation des Chefs Fokontany aux droits humains, l’importance de l’état civil dans la lutte contre la corruption, ainsi que le partage d’expériences. Ces éléments reflètent une compréhension plus globale du rôle stratégique de l’état civil dans la gouvernance locale et les droits fondamentaux.
Enfin, l’ensemble des témoignages indique une acquisition globale de connaissances autour de l’état civil, ce qui contribue à renforcer la professionnalisation des acteurs impliqués.
Utilisation des compétences pour plus de 93% des agents formés
Les résultats montrent une appropriation étendue des savoirs théoriques et pratiques par les agents de l’état civil, traduisant une transformation effective des compétences en actions concrètes. Plusieurs agents ont su mobiliser les connaissances acquises dans leur quotidien professionnel, à travers un meilleur respect des procédures (déclarations, enregistrements, transcription) et une tenue rigoureuse des registres (registre de mariage, registres de transmission, table quinquennale, etc.). La traçabilité, la célérité du travail, l’accueil des usagers et la qualité du service ont été mentionnées comme significativement améliorées.
Par ailleurs, de nombreuses initiatives de sensibilisation et d’échanges ont vu le jour. L’organisation de réunions avec les Chefs Fokontany pour informer et inciter la population à déclarer les faits d’état civil dans les délais légaux constitue un levier clé de l’ancrage communautaire. Des efforts de partage d’expérience entre agents et de formation des collègues ou nouveaux agents ont aussi été signalés, renforçant la cohésion des équipes et la pérennisation des acquis.
Certains agents ont également engagé des démarches de standardisation et d’uniformisation du service public, notamment au niveau des six arrondissements de la Commune Urbaine d’Antananarivo, témoignant d’une volonté d’harmoniser les pratiques pour un service plus cohérent et fiable. La communication avec les usagers et la mise en place de tableaux d’affichage illustrent un souci croissant de transparence et de lisibilité du service.
Enfin, des actions éducatives ont été entreprises, telles que l’éducation parentale, la sensibilisation sur la reconnaissance des enfants ou encore la séparation des registres pour les mariages de mineurs, soulignant la montée en compétence des agents sur des aspects juridiques, éthiques et sociétaux.
Retombées observées auprès de 94% des agents ayant utilisé les compétences
Les retombées de la formation sur l’état civil sont globalement très positives, tan', '100 %', 2024, 100);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS2', 'PROJ_A11', 'Lutte contre la désinformation', 'Effets du renforcement des capacités des acteurs de la société civile',
   'synthese', 'Acquisition des compétences pour 100% des acteurs de la société civile formés
Les connaissances acquises à travers la formation sur les enjeux de lutte contre la désinformation témoignent d’un renforcement significatif des compétences des participants en matière de lutte contre la désinformation et de traitement rigoureux de l’information. L’essentiel des acquis porte sur la vérification, le recoupement et la confrontation des sources, ainsi que sur la capacité à diffuser des informations fiables, en particulier dans des contextes sensibles comme les périodes électorales.
Les participants ont également approfondi leur compréhension des types de désinformation (désinformation, mésinformation, mal information) et des techniques de fact-checking, incluant l’analyse des textes, images et vidéos. Cette maîtrise s’accompagne d’une meilleure connaissance des outils de vérification existants, ainsi que d’un développement du savoir-être professionnel : responsabilité des médias, posture en situation de crise, sensibilisation des auditoires, ou encore éthique journalistique.
Par ailleurs, plusieurs retours soulignent l’intégration de savoirs transversaux, tels que les enjeux migratoires, la cybercriminalité, ou encore l’usage responsable de l’intelligence artificielle dans le traitement de l’information. Des actions de restitution et de sensibilisation ont même été menées au niveau local, montrant un réel engagement à restituer les acquis au sein des communautés et à renforcer la culture de l’information fiable.
En somme, la formation a permis aux bénéficiaires de devenir plus critiques, responsables et outillés face aux flux d’information, consolidant ainsi leur rôle dans la prévention des fake news, la promotion de l’information vérifiée et la construction d’un espace médiatique plus sain et professionnel.
Utilisation des compétences pour plus de 69% des acteurs de la société civile formés
L’analyse des réponses montre que les compétences acquises en matière de vérification de l’information (fact-checking) ont été activement réinvesties dans une diversité de contextes professionnels et communautaires. De nombreux participants affirment désormais vérifier systématiquement les sources, les faits, les images et les contenus avant de publier ou partager des informations, notamment dans des métiers comme le journalisme, l’enseignement, la communication ou la production de contenu audiovisuel.
Plusieurs ont intégré ces savoir-faire dans leurs pratiques professionnelles, par exemple à travers la rédaction d’articles fiables, la réalisation de reportages, l’analyse critique de discours de haine, ou encore la coproduction d’émissions radio axées sur l’éducation aux médias. Des enseignants ont utilisé les compétences acquises pour former leurs élèves à la recherche et au tri de l’information, tandis que d''autres ont lancé des enquêtes, causeries éducatives et restitutions communautaires, contribuant ainsi à la sensibilisation du public.
Par ailleurs, la formation a favorisé une prise de responsabilité accrue. Les bénéficiaires se montrent plus vigilants, plus professionnels et plus rapides dans le traitement, la diffusion et la validation des informations. Ils s’investissent dans la lutte contre la désinformation, parfois à travers des actions de plaidoyer, de communication pour le changement de comportement, ou encore via la coordination de projets et des partenariats inter-médias.
Enfin, plusieurs participants ont pu mettre en place des outils pédagogiques ou numériques pour partager leurs acquis, aussi bien en ligne (via LinkedIn ou des vidéos explicatives) que dans leur entourage direct. Cette dynamique montre une volonté collective de rendre l’espace informationnel plus fiable, inclusif et résilient, en s’appuyant sur les compétences développées lors de la formation.
Retombées observées auprès de 69% des acteurs ayant utilisé les compétences
Les retombées observées après l''investissement des connaissances acquises montrent une réelle dynam', '100 %', 2024, 110);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS2', 'PROJ_A12', 'Processus démocratique', 'Effets du renforcement des capacités des acteurs des processus électoraux',
   'synthese', 'Acquisition des compétences pour 100% des acteurs impliqués dans les processus démocratiques
La formation a permis aux participants d’acquérir des compétences solides sur plusieurs thématiques clés liées à la citoyenneté, à la gouvernance et à l’action publique. Elle a d’abord renforcé la compréhension des principes fondamentaux de la démocratie et des droits humains, en mettant l’accent sur les libertés fondamentales, l’égalité, la participation citoyenne, et le rôle de l’État dans la protection des droits.
Les participants ont également été formés aux principes et techniques de l’observation électorale, leur permettant de suivre les processus électoraux avec rigueur, objectivité et professionnalisme. Cette capacité est cruciale pour assurer la transparence des scrutins et contribuer à la crédibilité du processus démocratique.
Par ailleurs, l’apprentissage de la rédaction juridique a permis de mieux structurer et formaliser des documents à portée légale (rapports, notes, argumentaires, etc.), en respectant les normes juridiques et les exigences de clarté et de précision.
Enfin, les participants ont été initiés aux techniques d’évaluation des politiques publiques, leur donnant les outils nécessaires pour analyser, mesurer et critiquer les actions publiques sur la base d’indicateurs pertinents. Cela favorise une approche plus responsable, fondée sur les résultats et l’amélioration continue de la gouvernance.
Dans l’ensemble, cette formation a contribué à renforcer les capacités d’analyse, d’action citoyenne et de plaidoyer des bénéficiaires, leur permettant d’être des acteurs plus engagés, critiques et outillés dans leur environnement professionnel ou communautaire.
Utilisation des compétences pour plus de 43% des acteurs impliqués dans les processus démocratiques
À la suite des formations dispensées, les bénéficiaires ont largement réinvesti les compétences acquises à travers une diversité d’actions concrètes allant de la participation citoyenne à la gouvernance locale, en passant par le plaidoyer, l’éducation civique et l’observation électorale. Plusieurs d’entre eux ont mobilisé leurs connaissances pour organiser ou participer à des observations électorales, contribuant ainsi à garantir la transparence des scrutins législatifs, provinciaux ou communaux. Des initiatives de médiation et de gestion de conflits ont également vu le jour, illustrant la mise en pratique des principes de dialogue, de résilience et de gestion démocratique des tensions.
Dans le domaine du plaidoyer, des actions ont été entreprises pour influencer les politiques publiques, notamment en Guinée et en République Démocratique du Congo où des plaidoyers ont été élaborés en faveur de réformes constitutionnelles, de la reconnaissance des institutions de défense des droits humains ou encore de la libération de figures politiques. D''autres  ont mis en place ou renforcé des mécanismes de participation citoyenne, via la création de clubs scolaires sur les droits humains, l’organisation de séminaires de sensibilisation, ou encore l’accompagnement d’associations de jeunes et de femmes dans leur autonomisation politique et économique.
Sur le plan professionnel, de nombreux participants ont amélioré leur pratique de communication politique et institutionnelle en appliquant des techniques de rédaction juridique, de communication de crise ou de gestion de projets. Certains ont également renforcé les compétences de leurs collègues via des formations internes, notamment en matière de droits humains, de processus électoraux ou de gestion associative.
Enfin, plusieurs témoignages soulignent une transformation personnelle significative : un sens accru des responsabilités, une rigueur renforcée dans l’analyse des informations, une plus grande aisance dans les échanges institutionnels, ainsi qu’une meilleure capacité à défendre les droits humains dans des contextes parfois sensibles. Ces retombées confirment l’impact durable des compétences acquises, tant au niveau individuel', '100 %', 2024, 120);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS2', 'PROJ_A13', 'Paix et stabilité', 'Effets de la participation francophone dans les opérations de maintien de la paix',
   'synthese', 'Acquisition des compétences pour 100% des acteurs impliqués dans les opérations de maintien de la paix
Les connaissances acquises à travers cette formation sont à la fois techniques, humaines et relationnelles, avec un fort accent sur la communication, la pédagogie et l’ouverture interculturelle. Plusieurs participants soulignent l’apport précieux en rédaction, expression orale et capacité à prendre la parole en public, des compétences devenues essentielles pour assurer des rôles de représentation, de formation ou de coordination. Grâce aux modules pédagogiques, ils ont pu renforcer leur aptitude à transmettre efficacement leurs savoirs et à développer les capacités des équipes qu’ils encadrent.
L’acquisition de compétences relationnelles et interpersonnelles est également centrale : l’écoute, l’empathie, l’esprit d’équipe et le respect de la diversité culturelle sont régulièrement mentionnés. Ces qualités ont permis non seulement un travail collaboratif plus fluide mais aussi une meilleure compréhension des contextes internationaux et des collègues venus d''autres pays. Cela s’est traduit par des échanges fructueux, un enrichissement linguistique, et une introspection personnelle et professionnelle sur ses propres valeurs, pratiques et engagements dans les domaines policier, militaire ou civique.
Enfin, les relations institutionnelles et les échanges entre pairs ont permis d’ouvrir de nouvelles perspectives professionnelles en favorisant la coopération, le partage d’expériences et le développement de réseaux de confiance entre institutions et acteurs issus de contextes variés. L’ensemble de ces acquis renforce l’aptitude des participants à évoluer dans des environnements multiculturels, exigeants et en constante mutation, en misant sur la rigueur, la pédagogie, et la collaboration.
Utilisation des compétences pour plus de 75% des agents formés
L’utilisation des compétences acquises varie fortement selon les parcours et les opportunités professionnelles des participants, mais plusieurs tendances ressortent. D’abord, la valorisation de la langue française est l’un des apports les plus fréquemment cités : de nombreux participants affirment avoir amélioré leur capacité à parler, lire, écouter et écrire en français, ce qui leur a permis de mieux communiquer au quotidien avec leurs collègues, de participer à des échanges professionnels, ou de dialoguer avec la presse étrangère. Certains évoquent également une plus grande confiance en eux lors de discussions en contexte francophone, notamment dans des environnements multinationaux.
Sur le plan professionnel, plusieurs participants indiquent avoir utilisé leurs compétences en gestion, logistique, coordination humanitaire ou résolution de conflits, que ce soit dans des contextes administratifs, humanitaires ou policiers. D''autres participants ont pu intégrer ces acquis dans des fonctions d’instruction, de formation ou de communication, notamment au sein d’instituts nationaux ou dans le cadre de missions de service public. Quelques témoignages mettent en lumière une application des savoirs dans la médiation et la négociation, en particulier dans des situations sensibles ou de gestion de tensions.
Cependant, une partie importante des répondants indique qu’elle n’a encore eu  l’occasion d’appliquer ces compétences dans le cadre de missions internationales ou d''opérations de paix. Néanmoins, plusieurs d’entre eux expriment leur volonté ou leur préparation en vue d’une future participation, en particulier à travers le passage de certifications ou la recherche d’opportunités avec les Nations Unies.
Enfin, l''expérience de la formation semble avoir suscité une ouverture culturelle, un esprit d’équipe et un respect renforcé de la diversité, autant de qualités appréciées dans les environnements multiculturels. Pour certains, cette formation a aussi stimulé une auto-préparation continue, avec une volonté de maintenir ou renforcer les acquis, même en dehors des contextes opérationnels directs.
Ret', '100 %', 2024, 130);

-- ═══════════════════════════════════════════════════════
-- PS3 — Langue française, vecteur de développement durable
-- ═══════════════════════════════════════════════════════
INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS3', 'PROJ_A14', 'Fonds Francophonie avec Elles', 'Effets du Fonds sur les conditions de vie des femmes',
   'synthese', 'Acquisition des compétences l’ensemble des femmes soutenues :
Les actions de renforcement de capacités mises en œuvre ont permis aux femmes bénéficiaires de développer un large éventail de compétences techniques et entrepreneuriales, favorisant leur autonomisation économique et sociale. Ces formations ont principalement porté sur trois grands axes : l''agriculture et l’élevage, la transformation et la valorisation des produits ainsi que la gestion d’activités génératrices de revenus (AGR).
Dans le domaine agro-sylvo-pastoral, les femmes ont acquis des compétences en production maraîchère, culture vivrière (maïs, soja, manioc), apiculture, et techniques de gestion durable des ressources naturelles. Tenant compte des besoins exprimés et de la situation locale, une attention particulière a été accordée à l’élevage avec des formations spécialisées en aviculture (y compris techniques améliorées pour les races locales), élevage porcin, caprin, ovin, et production de volailles en poulaillers modernisés. Certaines femmes ont également été formées à la production de provendes, au compostage et à la gestion des déchets organiques pour une agriculture plus écologique.
Concernant la transformation artisanale et agroalimentaire, les femmes ont été formées à la transformation de produits agricoles (sésame, arachide, riz, attiéké), à la fabrication de produits d’hygiène (savons), de pâtisseries et de produits alimentaires de qualité. D’autres ont appris à fabriquer du charbon écologique à base de déchets recyclés ou de papier, à confectionner des objets artisanaux (tissus, sacs à base de nattes plastiques, gadgets), ou encore à produire des arbres fruitiers et à conserver les produits agroalimentaires.
Sur le plan entrepreneurial et social, les bénéficiaires ont acquis des compétences clés en gestion financière, marketing, épargne, vente, et création/gestion des AGR. Des modules sur la vie coopérative, le leadership féminin, la prévention des violences basées sur le genre (VBG) et la valorisation de l’estime de soi ont aussi été dispensés. L’accent a été mis sur l’importance de la relation client, la planification des activités, la promotion des produits et le développement de l’esprit entrepreneurial. Certaines femmes ont en outre bénéficié d’un accompagnement en alphabétisation, en numérique et en formation professionnelle (photographie, dessin, peinture, staff).
En parallèle, des formations ont été dispensées sur la vie coopérative, les compétences de vie courante, l’estime de soi, la protection contre VBG, le leadership féminin, ainsi que sur la gestion hygiénique des menstruations. Ces modules transversaux ont renforcé la capacité des femmes à gérer leur quotidien, à interagir avec les clients avec professionnalisme, à s’organiser et à prendre des décisions éclairées dans la sphère privée comme publique.
Enfin, l’accès à l’alphabétisation et à des compétences de base en informatique et communication numérique a permis à plusieurs femmes de renforcer leur autonomie, d''élargir leur réseau et d''envisager des projets entrepreneuriaux avec davantage de confiance et d’indépendance.
Ces formations ont permis non seulement un renforcement des compétences techniques, mais également un véritable changement de posture chez les participantes qui deviendraient mieux préparées pour saisir les opportunités économiques, à créer leurs propres activités et à contribuer activement à la vie de leurs communautés.
Amélioration des conditions de vies auprès de 100% des femmes soutenues
Le projet a eu un impact significatif sur la situation économique des femmes bénéficiaires. Nombre d''entre elles ont vu leurs revenus augmenter grâce à la diversification de leurs activités, à leur adhésion dans des coopératives agricoles, à une meilleure organisation du travail et à l''accès à de nouveaux débouchés.
Certaines ont pu ouvrir un compte bancaire, accéder à des sources de financement comme les microcrédits, et financer leur activité de manière autonome. Cette amélior', '100 %', 2024, 200);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS3', 'PROJ_A18', 'Environnement et Climat', 'Effets des actions face aux enjeux environnementaux et climatiques',
   'synthese', 'Acquisition des compétences pour l’ensemble des négociatrices accompagnées :
À l’issue de leur formation, les négociatrices ont acquis une compréhension approfondie des principaux cadres multilatéraux en matière d’environnement, notamment les conventions des Nations unies sur les changements climatiques (CNUCC), la biodiversité (CBD) et la lutte contre la désertification (UNCCD). Elles maîtrisent désormais les parcours, processus décisionnels et rôles des différents acteurs impliqués dans ces négociations internationales.
Elles ont renforcé leur expertise en techniques de négociation multilatérale, incluant la rédaction de textes de négociation, l’analyse des positions des parties, et la formulation d’ambitions en matière d’atténuation des émissions de gaz à effet de serre. Leur capacité à identifier et traiter les sujets clés des négociations s’est également accrue : finance climat, transparence, mécanismes de coopération, pertes et préjudices, transfert de technologies, adaptation et atténuation.
Les négociatrices ont par ailleurs développé des compétences pratiques en finance liée aux négociations sur le climat (NOGQ) ainsi qu’en réseautage stratégique et communication, leur permettant de mieux interagir avec d''autres parties prenantes. Enfin, la pratique du bilinguisme (français – anglais) a été consolidée, renforçant ainsi leur capacité à s’exprimer avec aisance dans les enceintes internationales.
Ces compétences font d’elles des actrices prêtes à représenter efficacement leur pays ou région dans les espaces internationaux de négociation environnementale.
Valorisation des compétences acquises par 86% des négociatrices pour mieux défendre les positions de leurs pays:
À la suite de la formation dispensée par l’Institut de la Francophonie pour le développement durable (IFDD), les négociatrices formées ont progressivement intégré les délégations officielles de leurs pays aux conférences internationales sur le climat, notamment les Conférences des Parties (CdP). Leur participation ne s’est pas limitée à une simple présence : elles ont été actrices à part entière des négociations, prenant en charge des thématiques spécifiques comme le genre, les pertes et préjudices, le développement et transfert de technologies ou encore la finance climat.
« Mes responsables m''ont intégrée à l''équipe qui accompagne les ministres pendant leur séjour à la COP. De plus, je suis en charge d''encadrer les nouvelles jeunes négociatrices durant leur séjour. »
« J''ai particip  avec l''épuipe de mon pays aux négociations à Charm El Cheick  et à  Bonn. »
Certaines négociatrices ont même été désignées cheffes de file ou points focaux nationaaux, témoignant ainsi de la reconnaissance institutionnelle de leurs compétences.
« Les informations reçues sur l''élaboration des CDN, le contenu des plans d''adaptation nationaux, les questions relatives à l''atténuation, les finances, les préparations de participation des délégations aux COP, la technique de prise de parole lors des négociations ont de fait de moi est un acteur invité au Mali dans toutes les thématiques liées au changement climatique. J''arrive à produire de bons Termes de référence pour la mobilisation des fonds dans le cadre de mise des activités au niveau communautaire. J''ai été désigné comme chef de fil des négociateurs et négociatrices maliens. »
« J’ai été désignée point focal pour le Fonds bleu du Bassin du Congo ».
« Dans l’équipe de négociations de mon pays, je suis en charge des thématiques genre et changement climatique. C’est grâce aux formations de l’IFDD que j’ai été nommée point focal genre et changement climatique auprès de la CCNUCC. »
Parallèlement, ces femmes ont été pleinement impliquées dans les processus nationaux de préparation aux CdP : participation aux comités techniques, contribution à l’élaboration des CDN, des PNA et des rapports nationaux, rédaction de notes conceptuelles pour la mobilisation de financements climatiques. Leur expertise nouvellement acquise a renforcé leur rô', '86 %', 2024, 210);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS3', 'PROJ_A19', 'Bassin du Congo — Agriculture durable', 'Effets du renforcement des capacités des jeunes acteurs du Bassin du Congo',
   'synthese', 'Acquisition de compétences des jeunes et femmes formées sur l’agriculture durable
Les différentes formations organisées ont permis aux jeunes de développer une large gamme de compétences techniques et pratiques. Ils ont acquis des savoir-faire en agroécologie, notamment en matière de fabrication de compost, de biopesticides, de techniques de rotation culturale, de polyculture et d’irrigation efficiente. Ces compétences leur permettent désormais de conduire des exploitations agricoles résilientes, à la fois productives et respectueuses de l’environnement.
En parallèle, les jeunes ont été formés à la gestion et à la transformation des déchets, qu’ils soient plastiques ou organiques. Ils maîtrisent aujourd’hui les techniques de recyclage, de valorisation et de production de biens à partir de matériaux récupérés. La création de meubles décoratifs à base de pneus usagés, la transformation de déchets plastiques en objets utiles ou encore la fabrication de charbon écologique à faible émission sont autant de compétences qui s''inscrivent dans une logique d''économie circulaire.
Au-delà des compétences techniques, ces initiatives ont renforcé les capacités entrepreneuriales des jeunes : planification agricole, commercialisation des produits transformés, mais aussi leadership communautaire.
Les jeunes accompagnés ont appris à mobiliser leurs communautés autour d’enjeux environnementaux, à conduire des actions collectives et à promouvoir des modes de production et de consommation durables.
En somme, ils ont développé une autonomie professionnelle et sociale, doublée d’un fort engagement citoyen, leur permettant de jouer un rôle actif dans la transition écologique de leur territoire.
Utilisation des compétences par plus de 65% des jeunes et femmes formées sur l’agriculture durable
Les jeunes formés ont activement mis en œuvre les compétences acquises à travers une diversité d’activités pratiques, principalement dans les domaines de l’agroécologie et de la gestion durable des ressources. En agriculture, ils ont remplacé l’usage des engrais chimiques par des engrais biologiques produits localement, à base de déchets organiques (compost, fiente de volaille, résidus végétaux, …). Grâce à des analyses de sol préalables, ils adaptent désormais les apports nutritifs selon les besoins réels du terrain, favorisant ainsi une fertilisation naturelle et durable. De nombreux jeunes appliquent aussi des techniques telles que la rotation des cultures, le semis en poquet, le respect des écartements, ainsi que la lutte intégrée à l’aide de plantes répulsives pour se passer des pesticides chimiques.
« J’ai désormais une croissance rapide des plantes »
« Je constate une baisse du taux d''infestation »
« J’observe une nette amélioration de la production »
« J''ai moins de mortalité et les sujets sont plus solides et prennent rapidement du poids »
« La nouvelle technique des PIF (Plantes issues des fragments de tiges) que j’ai acquise m’a permis un développement plus accru de ma production de bananes. »
La gestion écologique des déchets constitue un autre domaine clé d’application. Plusieurs jeunes ont mis en place des dispositifs de compostage dans leurs fermes ou jardins, utilisé les matières organiques enfouies pour restaurer les sols et intégré les résidus de culture pour enrichir leurs parcelles. Certains ont même associé leurs cultures à des projets de recyclage ou de reboisement, intégrant ainsi des pratiques d’agroforesterie. D’autres ont conçu des emballages biodégradables, des produits écoresponsables ou encore des systèmes de purification de l’eau basés sur des technologies durables.
Sur le plan entrepreneurial, les jeunes ont démontré une forte capacité à structurer leurs activités agricoles ou environnementales : mise en place de planches de culture, création de pépinières, construction de germoirs, suivi des cultures, gestion des intrants biologiques. Certains ont même amorcé des projets pilotes sur des parcelles de 25 m² à 50 ares, appliquant rigou', '65 %', 2024, 220);

INSERT INTO resultats_era (ps_id, projet_code, projet_nom, titre_section, niveau, contenu, chiffre_cle, annee_exercice, ordre) VALUES
  ('PS3', 'PROJ_A19', 'Bassin du Congo — Innovations climatiques', 'Effets induits par la mise en place des solutions et innovations climatiques',
   'synthese', 'Introduction et adoption de 19% des innovations climatiques par les jeunes
Les jeunes financés ont développé un e éventail d’innovations climatiques et environnementales, apportant des solutions concrètes et adaptées aux défis locaux. Dans le domaine agricole, plusieurs d’entre eux ont adopté des techniques agricoles résilientes telles que la rotation des cultures, l’usage de semences résistantes à la sécheresse ainsi que la pratique de la polyculture pour réduire les risques liés aux changements climatiques. Ils ont aussi généralisé la biofertilisation et la lutte intégrée contre les ravageurs en produisant localement du compost et des biopesticides, contribuant ainsi à une agriculture plus durable moins dépendante des intrants chimiques.
« Je mets en pratique les capacités acquises pour fabriquer les biopesticides et les biofertilisants, la confection des planches pour faciliter le semis et le suivi des cultures.  L''application de ces techniques contribue également la préservation de l''environnement ;»
En parallèle, des solutions ont été introduites pour assurer une gestion durable de l’eau, essentielle dans des zones de plus en plus soumises à la sécheresse. Des systèmes d’irrigation améliorés et la création de retenues d’eau ont permis d’optimiser l’utilisation des ressources hydriques assurant une meilleure productivité agricole tout en préservant les écosystèmes locaux.
« Après l’application de ces compétences, nous avons réussi à concevoir un prototype fonctionnel capable de purifier l’eau de manière efficace. Lors de la cérémonie de clôture du projet PADTIE, les participants ont pu tester l’eau traitée et ont exprimé leur satisfaction quant à sa qualité. Ce succès a renforcé la crédibilité de notre solution et ouvert des opportunités pour son amélioration et son déploiement à plus grande échelle. »
Dans le domaine des énergies renouvelables, plusieurs jeunes ont mis en œuvre des solutions énergétiques durables comme l’utilisation de l’énergie solaire pour alimenter leurs installations ou la production de biogaz à partir de déchets organiques. Une innovation notable est la fabrication de charbon écologique, avec un système de carbonisation propre qui capte la fumée et la transforme en vinaigre de bois, limitant les émissions polluantes tout en générant un sous-produit utile pour l’agriculture.
« J’ai pu créer un nouveau procédé qui utilise un carbonisateur qui capte la fumée pendant la carbonisation pour le transformer en vinaigre de bois. »
Dans le domaine de la biodiversité, les jeunes ont œuvré à la protection et à la restauration des écosystèmes locaux, notamment à travers la réduction des déchets plastiques et la valorisation des déchets agricoles. Des initiatives de recyclage ont permis de transformer des déchets (plastiques, pneus, biodéchets) en objets décoratifs, meubles, composts ou biopesticides, contribuant ainsi à la préservation de l’environnement et à la lutte contre la pollution. Ces projets s’accompagnent souvent d’activités de sensibilisation environnementale, parfois appuyées par des outils innovants comme la réalité virtuelle, renforçant ainsi l’éducation à la protection de la nature.
« Les formations que j’ai suivies m’ont permis de fabriquer des matériaux de construction à base de déchets »
Enfin, la valorisation du terroir par la transformation locale de fruits et légumes (compotes, céréales) et l''intégration de la technologie agricole ont permis de créer de nouvelles opportunités économiques tout en favorisant une production locale durable.
L’ensemble de ces actions témoigne de l''engagement des jeunes pour un développement durable, alliant innovation, écologie et inclusion sociale.
Amélioration du bien-être pour 68% des populations ayant adopté les innovations climatiques
L’intégration des innovations écologiques et agricoles par les jeunes a engendré des changements profonds sur le bien-être des populations. L’adoption de techniques agricoles résilientes, de solutions énergétiques durables et de', '19 %', 2024, 230);
